import React, { useState, useEffect } from 'react';

const EditPurchase = ({ purchase, handleUpdate, locations, materials, vendors }) => {
  
  
  const [editedPurchase, setEditedPurchase] = useState({ ...purchase });

  useEffect(() => {
    const editedvendorname = vendors.find((vendor) => vendor.name === purchase.vendor);
    const editedlocationname = locations.find((loc) => loc.locationname === purchase.location);
  
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendorname: editedvendorname ? editedvendorname.name : '',
      vendor: editedvendorname ? editedvendorname.vendorid : '',
      locationname: editedlocationname ? editedlocationname.locationname : '',
      location: editedlocationname ? editedlocationname.id : '',
    }));
  }, [purchase, vendors, locations]);
  
  console.log('editedPurchase:', editedPurchase);
  console.log('myPurchase:', purchase);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
    
    // If the name of the select element is 'vendor', update 'vendorname' accordingly
    if (name === 'location') {
      const selectedLocation = locations.find((loc) => loc.locationname === value);
      if (selectedLocation) {
        setEditedPurchase((prevPurchase) => ({
          ...prevPurchase,
          location: selectedLocation.id,
          locationname: selectedLocation.locationname,
        }));
      } else {
        setEditedPurchase((prevPurchase) => ({
          ...prevPurchase,
          location: '',
          locationname: '',
        }));
      }
    };
    if (name === 'vendor') {
      const selectedVendor = vendors.find((vendor) => vendor.name === value);
      if (selectedVendor) {
        setEditedPurchase((prevPurchase) => ({
          ...prevPurchase,
          vendor: selectedVendor.vendorid,
          vendorname: selectedVendor.name,
        }));
      } else {
        setEditedPurchase((prevPurchase) => ({
          ...prevPurchase,
          vendor: '',
          vendorname: '',
        }));
      }
    }


  };
  

  const handleSave = () => {
    handleUpdate(editedPurchase);

    // Check if vendor or price is changed to post to materialchangesAPI
    if (editedPurchase.vendorname !== purchase.vendor || editedPurchase.price !== purchase.price) {
      const materialChangeData = {
        material_id: editedPurchase.materialid,
        vendor: editedPurchase.vendor,
        price: editedPurchase.price,
      };

      // Make a POST request to materialchangesAPI
      fetch('http://localhost:8081/materialchangesAPI', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(materialChangeData),
      })
        .then((response) => response.json())
        .then((data) => {
          console.log('Material changes saved:', data);
        })
        .then(() => {
          setEditingPurchase(null);
        })
        .catch((error) => {
          console.error('Error saving material changes:', error);
        });
    }
  };

  // Check if material.extras !== 1 to hide "Width" and "Lot No" inputs
  const hideWidthAndLotNo =
  materials.find((material) => material.matid === editedPurchase.materialid)?.extras !== 1;


  return (
    <div className="edit-purchase">
      <h2>Edit Purchase</h2>
      <div>
      <label>
        Location:
        <select name="location" value={editedPurchase.locationname} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.locationname}>
              {location.locationname}
            </option>
          ))}
        </select>
      </label>
      </div>      
      {hideWidthAndLotNo ? null : (
        <>
          <div>
            <label>
              Width:
              <input type="text" name="width" value={editedPurchase.width} onChange={handleChange} />
            </label>
          </div>
          <div>
            <label>
              Lot No:
              <input
                type="text"
                name="lotnumber"
                value={editedPurchase.lotnumber}
                onChange={handleChange}
              />
            </label>
          </div>
        </>
      )}
      <div>
        <label>
          Quantity:
          <input
            type="text"
            name="quantity"
            value={editedPurchase.quantity}
            onChange={handleChange}
          />
        </label>
      </div>
      <div>
        <label>
          Price:
          <input type="text" name="price" value={editedPurchase.price} onChange={handleChange} />
        </label>
      </div>
      <div>
      <label>
        Vendor:
        <select name="vendor" value={editedPurchase.vendorname} onChange={handleChange} required>
          <option value="">Select a vendor</option>
          {vendors.map((vendor) => (
            <option key={vendor.vendorid} value={vendor.name}>
              {vendor.name}
            </option>
          ))}
        </select>
      </label>
      </div>
      <div>
        <button onClick={handleSave}>Save</button>
      </div>
    </div>
  );
};

export default EditPurchase;
